42	#if NV_TENSORRT_MAJOR >= 11 || (NV_TENSORRT_MAJOR == 10 && NV_TENSORRT_MINOR >= 13)
43	namespace
44	{
45	
46	void appendLunowudFlag(std::string& flags, std::string const& flag)
47	{
48	    if (flags.find(flag) != std::string::npos)
49	    {
50	        return;
51	    }
52	    if (!flags.empty())
53	    {
54	        flags += ' ';
55	    }
56	    flags += flag;
57	}
58	
59	std::string applyMyelinCompileWorkarounds(int32_t maxBatchSize)
60	{
61	    std::string lunowudFlags;
62	    char const* existingLunowud = std::getenv("__LUNOWUD");
63	    if (existingLunowud)
64	    {
65	        lunowudFlags = existingLunowud;
66	    }
67	#if NV_TENSORRT_MAJOR == 10 && (NV_TENSORRT_MINOR == 13 || NV_TENSORRT_MINOR == 14)
68	    appendLunowudFlag(lunowudFlags, "-peep:match_dual_gemm=off");
69	#endif
70	#if NV_TENSORRT_MAJOR >= 11 || (NV_TENSORRT_MAJOR == 10 && NV_TENSORRT_MINOR >= 15)
71	    appendLunowudFlag(lunowudFlags, "-mlir:autotune:num_threads=1");
72	    appendLunowudFlag(lunowudFlags, "-mlir:collective:fp4=off");
73	    appendLunowudFlag(lunowudFlags, "-cask_fusion:async_policy=1");
74	    if (maxBatchSize == 1)
75	    {
76	        appendLunowudFlag(lunowudFlags, "-peep:fc_h_fusion=off");
77	    }
78	#endif
79	    if (existingLunowud || !lunowudFlags.empty())
80	    {
81	        setenv("__LUNOWUD", lunowudFlags.c_str(), 1);
82	    }
83	    return lunowudFlags;
84	}
85	
86	} // namespace
87	#endif
88	
89	namespace
90	{
91	
92	std::string specDecodeType(Json const& config)
93	{
94	    return config.value("spec_decode_type", "none");
95	}
96	
97	std::string engineRole(Json const& config)
98	{
99	    return config.value("engine_role", "llm");
100	}
101	
102	bool isSpecDecodeBase(Json const& config, char const* type)
103	{
104	    return specDecodeType(config) == type && engineRole(config) == "base";
105	}
106	
107	bool isSpecDecodeDraft(Json const& config, char const* type)
108	{
109	    return specDecodeType(config) == type && engineRole(config) == "draft";
110	}
111	
112	bool isValidSpecDecodeType(std::string const& type)
113	{
114	    return type == "none" || type == "mtp" || type == "eagle3" || type == "dflash" || type == "gemma4_mtp";
115	}
116	
117	bool isValidEngineRole(std::string const& role)
118	{
119	    return role == "llm" || role == "base" || role == "draft";
120	}
121	
122	bool hasInputBinding(nvinfer1::INetworkDefinition const& network, char const* inputName)
123	{
124	    std::string_view const target{inputName};
125	    for (int32_t idx = 0; idx < network.getNbInputs(); ++idx)
126	    {
127	        if (std::string_view{network.getInput(idx)->getName()} == target)
128	        {
129	            return true;
130	        }
131	    }
132	    return false;
133	}
134	
135	std::optional<int64_t> getStaticInputDim(
136	    nvinfer1::INetworkDefinition const& network, char const* inputName, int32_t axis)
137	{
138	    std::string_view const target{inputName};
139	    for (int32_t idx = 0; idx < network.getNbInputs(); ++idx)
140	    {
141	        auto const* input = network.getInput(idx);
142	        if (std::string_view{input->getName()} != target)
143	        {
144	            continue;
145	        }
146	        nvinfer1::Dims const dims = input->getDimensions();
147	        if (axis >= dims.nbDims || dims.d[axis] <= 0)
148	        {
149	            return std::nullopt;
150	        }
151	        return dims.d[axis];
152	    }
153	    return std::nullopt;
154	}
