157	
158	LLMBuilder::LLMBuilder(
159	    std::filesystem::path const& onnxDir, std::filesystem::path const& engineDir, LLMBuilderConfig const& config)
160	    : mOnnxDir(onnxDir)
161	    , mEngineDir(engineDir)
162	    , mBuilderConfig(config)
163	{
164	}
165	
166	bool LLMBuilder::build()
167	{
168	    std::string trtVersion = std::to_string(NV_TENSORRT_MAJOR) + "." + std::to_string(NV_TENSORRT_MINOR) + "."
169	        + std::to_string(NV_TENSORRT_PATCH);
170	    LOG_INFO("Using TRT_VERSION=%s", trtVersion.c_str());
171	#if NV_TENSORRT_MAJOR >= 11 || NV_TENSORRT_MAJOR == 10 && NV_TENSORRT_MINOR >= 13
172	    std::string const lunowudFlags = applyMyelinCompileWorkarounds(mBuilderConfig.maxBatchSize);
173	    if (!lunowudFlags.empty())
174	    {
175	        LOG_INFO("Using __LUNOWUD=%s", lunowudFlags.c_str());
176	    }
177	#endif
178	
179	    // Load plugin library
180	    auto pluginHandles = loadEdgellmPluginLib();
181	
182	    // Parse model config
183	    if (!parseConfig())
184	    {
185	        return false;
186	    }
187	
188	    // Create builder and network
189	    auto [builder, network] = createBuilderAndNetwork();
190	    if (!builder || !network)
191	    {
192	        return false;
193	    }
194	
195	    // Determine ONNX file path
196	    std::string onnxFilePath;
197	    if (mBuilderConfig.maxLoraRank > 0)
198	    {
199	        onnxFilePath = (mOnnxDir / "lora_model.onnx").string();
200	        LOG_INFO("Parsing LoRA-enabled ONNX model: %s", onnxFilePath.c_str());
201	    }
202	    else
203	    {
204	        onnxFilePath = (mOnnxDir / "model.onnx").string();
205	        LOG_INFO("Parsing ONNX model: %s", onnxFilePath.c_str());
206	    }
207	
208	    // Parse ONNX model
209	    auto parser = parseOnnxModel(network.get(), onnxFilePath);
210	    if (!parser)
211	    {
212	        return false;
213	    }
214	
215	    // Print network information
216	    LOG_DEBUG("%s", printNetworkInfo(network.get(), "LLM").c_str());
217	
218	    LOG_DEBUG(
219	        "ONNX parsing complete. mNbKVCacheInputs=%d, mNumLinearAttnLayers=%d", mNbKVCacheInputs, mNumLinearAttnLayers);
220	
221	    // Create builder config
222	    auto config = createBuilderConfig(builder.get());
223	    if (!config)
224	    {
225	        return false;
226	    }
227	
228	    if (mBuilderConfig.profilingDetailed)
229	    {
230	        config->setProfilingVerbosity(nvinfer1::ProfilingVerbosity::kDETAILED);
231	        LOG_INFO("Profiling verbosity set to DETAILED");
232	    }
233	
234	    LOG_DEBUG("Builder config created. Setting up optimization profiles...");
235	
236	    // Setup optimization profiles
237	    if (!setupLLMOptimizationProfiles(*builder.get(), *config.get(), *network.get()))
