267	    nvinfer1::INetworkDefinition* network, std::string const& onnxFilePath)
268	{
269	    if (!network)
270	    {
271	        LOG_ERROR("Network is nullptr");
272	        return nullptr;
273	    }
274	
275	    // Create ONNX parser
276	    auto parser = std::unique_ptr<nvonnxparser::IParser>(nvonnxparser::createParser(*network, gLogger));
277	    if (!parser)
278	    {
279	        LOG_ERROR("Failed to create ONNX parser");
280	        return nullptr;
281	    }
282	
283	    // Parse ONNX model
284	    if (!parser->parseFromFile(onnxFilePath.c_str(), static_cast<int>(gLogger.getLevel())))
285	    {
286	        LOG_ERROR("Failed to parse ONNX file: %s", onnxFilePath.c_str());
287	        return nullptr;
288	    }
289	
290	    LOG_DEBUG("Successfully parsed ONNX model: %s", onnxFilePath.c_str());
291	    return parser;
