332	bool loadJsonConfig(std::string const& configPath, nlohmann::json& outConfig)
333	{
334	    std::ifstream configFileStream(configPath);
335	    if (!configFileStream.is_open())
336	    {
337	        LOG_ERROR("Failed to open config file: %s", configPath.c_str());
338	        return false;
339	    }
340	
341	    try
342	    {
343	        outConfig = nlohmann::json::parse(configFileStream);
344	        configFileStream.close();
345	        return true;
346	    }
347	    catch (nlohmann::json::parse_error const& e)
348	    {
349	        LOG_ERROR("Failed to parse config file %s: %s", configPath.c_str(), e.what());
350	        return false;
351	    }
352	}
353	
354	bool saveConfigWithBuilderInfo(
355	    std::filesystem::path const& engineDir, nlohmann::json const& modelConfig, nlohmann::json const& builderConfig)
356	{
357	    std::string const targetConfigPath = (engineDir / "config.json").string();
358	
359	    // Create a copy of model config and add builder config
360	    nlohmann::json configWithBuilder = modelConfig;
361	    configWithBuilder["builder_config"] = builderConfig;
362	
363	    // Write updated config
364	    std::ofstream targetConfigFile(targetConfigPath);
365	    if (!targetConfigFile.is_open())
366	    {
367	        LOG_ERROR("Failed to open target config file: %s", targetConfigPath.c_str());
368	        return false;
369	    }
370	
371	    targetConfigFile << configWithBuilder.dump(2);
372	    targetConfigFile.close();
373	
374	    if (!targetConfigFile)
375	    {
376	        LOG_ERROR("Failed to write config file: %s", targetConfigPath.c_str());
377	        return false;
378	    }
379	
380	    LOG_INFO("Saved config with builder info to %s", targetConfigPath.c_str());
381	    return true;
382	}
